-- 1. Family Law Attorney (Dissolution)
-- ──────────────────────────────────────────────────────────────────────────
UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Fam. Code §§ 2000-2406 (dissolution proceedings — petition, response, default, uncontested/contested, bifurcation, status-only judgment); Cal. Fam. Code §§ 760-860 (community property characterization — general presumption § 760, transmutation § 850-853, separate property § 770, commingling/tracing); Cal. Fam. Code §§ 2100-2113 (fiduciary duties between spouses — preliminary disclosure § 2104, final disclosure § 2105, sanctions for nondisclosure § 2107, set-aside § 2120-2129); Cal. Fam. Code §§ 1100-1103 (management/control of community property — duty of good faith § 1100(e), written consent for realty § 1102); Cal. Fam. Code §§ 4320-4326 (spousal support factors — marital standard of living, earning capacity, domestic violence, tax consequences); Cal. Fam. Code §§ 3400-3465 (UCCJEA — jurisdiction, inconvenient forum, emergency jurisdiction); Cal. Rules of Court 5.2-5.487 (family law rules — mandatory forms, declarations, income/expense); AAML Bounds of Advocacy standards; Cal. Rules of Professional Conduct 1.4, 1.7-1.10 (conflicts/communication)',
  standards_of_creation = 'Judicial Council mandatory forms: FL-100 (Petition), FL-110 (Summons), FL-120 (Response), FL-115 (Proof of Service of Summons), FL-141 (Declaration Re Service of Declaration of Disclosure), FL-150 (Income and Expense Declaration), FL-142 (Schedule of Assets and Debts), FL-160 (Property Declaration), FL-170 (Declaration for Default), FL-180 (Judgment), FL-190 (Notice of Entry of Judgment), FL-300 (Request for Order), FL-310 (Application for Order and Supporting Declaration), FL-311 (Child Custody and Visitation Application Attachment), FL-320 (Responsive Declaration), FL-341 (Child Custody and Visitation Order Attachment), FL-342 (Child Support Information and Order Attachment), FL-343 (Spousal/Partner Support Order Attachment); Cal. Rules of Court 5.111-5.125 (document format — caption, page layout, attachment numbering); DissoMaster/XSpouse guideline support calculations; Elkins Family Law Task Force recommendations (oral testimony rights, access to justice); UCCJEA declaration (FL-105/GC-120); property characterization worksheets (Moore/Marsden, Pereira/Van Camp calculations)',
  soc_controls = 'Preliminary declaration of disclosure served within 60 days of filing response (Fam. Code § 2104(f)); final declaration of disclosure or valid waiver before entry of judgment (Fam. Code § 2105); 6-month waiting period from service of petition/summons (Fam. Code § 2339(a)); UCCJEA jurisdiction verification before any custody order; community property disclosure completeness audit — all assets/debts listed; spousal support factor analysis documented (all 14 factors under § 4320); income and expense declaration accuracy verification (perjury declaration); proof of service for all filed documents; automatic temporary restraining orders (ATROS) compliance verification (FL-110 back side — Fam. Code § 2040); date of separation determination documentation (Fam. Code § 70); attorney fee disclosure compliance (Fam. Code § 2030-2034); judgment completeness review before submission; property division equal division verification or § 2603 special circumstances documentation'
