-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 1: Cal. Fam. Code §§ 3000-3465 — Custody and Visitation
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_cust_001', 'Custody Evaluator (730 Evaluator)', 'STATE_STATUTE', 'CA',
'Cal. Fam. Code §§ 3000-3465',
'Fam. Code §§ 3000-3465',
'California Child Custody and Visitation — Best Interest, Joint Custody, DV Presumption, UCCJEA',
'Comprehensive statutory framework governing all child custody and visitation determinations in California. Section 3011 establishes the best interest of the child standard with specific factors: health, safety, and welfare of the child; history of abuse by either parent; nature and amount of contact with both parents; habitual or continual illegal use of controlled substances or alcohol. Section 3020 declares legislative policy favoring frequent and continuing contact with both parents after separation. Section 3044 creates a rebuttable presumption against custody to a parent who committed domestic violence within the past 5 years — perpetrator must demonstrate by preponderance of evidence that custody is in child best interest using 7 specified factors. Section 3040 establishes custody preference order: both parents jointly, then either parent. UCCJEA (§§ 3400-3465) governs interstate jurisdiction — home state jurisdiction § 3421, exclusive continuing jurisdiction § 3422, emergency jurisdiction § 3424.',
'["Best interest of child is paramount standard for all custody determinations (§ 3011)","Health, safety, and welfare of child are primary concerns (§ 3011(a))","History of abuse by either parent against child or other parent must be considered (§ 3011(b))","Nature and amount of contact with both parents must be considered (§ 3011(c))","Habitual substance abuse must be considered (§ 3011(d))","Frequent and continuing contact with both parents is declared state policy (§ 3020)","Joint custody preferred when in best interest (§ 3080)","Rebuttable DV presumption against joint or sole custody to DV perpetrator (§ 3044)","DV presumption requires perpetrator to meet 7 rebuttal factors by preponderance (§ 3044(b))","No preference for custody based on sex of parent (§ 3040(a))","Child''s wishes considered if age-appropriate (§ 3042)","Child cannot be forced to state custodial preference (§ 3042(b))","UCCJEA: home state jurisdiction is primary basis (§ 3421)","UCCJEA: exclusive continuing jurisdiction until all parties leave state (§ 3422)","UCCJEA: emergency jurisdiction for DV/abuse situations (§ 3424)","Court must consider history of false allegations of child abuse (§ 3027.5)","Friendly parent factor — willingness to allow frequent contact (§ 3040(a)(1))","Custody order must specify custodial time in detail (§ 3083/3086)","Move-away requires showing of changed circumstances (LaMusga factors)","Parental abduction risk factors must be assessed (§ 3048)"]',
'[{"section":"3011","description":"Best interest factors — health/safety/welfare, DV history, contact, substance abuse"},{"section":"3020","description":"Legislative policy — frequent and continuing contact with both parents"},{"section":"3040","description":"Custody order preference — joint, then either parent, no sex-based preference"},{"section":"3042","description":"Children''s wishes — age-appropriate consideration, no forced choice"},{"section":"3044","description":"DV presumption — rebuttable presumption against custody to perpetrator, 7 rebuttal factors"},{"section":"3080-3089","description":"Joint custody — request, terms, access to records, specified vs. unspecified"},{"section":"3100-3105","description":"Visitation rights — reasonable visitation, supervised visitation, grandparent visitation"},{"section":"3110-3118","description":"Custody evaluations — appointment, qualifications, training, report requirements"},{"section":"3120-3121","description":"Equal access — both parents entitled to access records, school, activities"},{"section":"3150-3153","description":"Minor''s counsel — appointment, duties, access to information, confidentiality"},{"section":"3160-3186","description":"Mediation — mandatory before custody hearing, recommending/non-recommending counties"},{"section":"3190-3192","description":"Court-ordered counseling — maximum 1 year, court review"},{"section":"3400-3465","description":"UCCJEA — interstate jurisdiction, home state, emergency jurisdiction, inconvenient forum"}]',
'["FL-311","FL-341","FL-341(B)","FL-341(C)","FL-341(D)","FL-341(E)","custody_evaluation_report","FCS_mediation_recommendation","parenting_plan","move_away_motion","DV_declaration_custody","UCCJEA_declaration","FL-105","visitation_schedule","supervised_visitation_order","child_interview_report"]',
'["family-law-custody-audit","child-custody-evaluation","dv-screening-assessment","uccjea-jurisdiction-analysis"]',
'California Superior Court — Family Law Division', 1, '1994-01-01', 1, datetime('now'), datetime('now'));


-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 2: Cal. Fam. Code §§ 6200-6389 — DVPA
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_dvpa_001', 'Domestic Violence Attorney (Petitioner/Respondent)', 'STATE_STATUTE', 'CA',
'Cal. Fam. Code §§ 6200-6389',
'DVPA',
'California Domestic Violence Prevention Act — Protective Orders, Firearms, Custody Presumption',
'The DVPA provides the primary civil remedy for domestic violence in California. Section 6300 authorizes issuance of ex parte protective orders upon reasonable proof of past act of abuse. Abuse is defined broadly under § 6203 to include intentionally or recklessly causing bodily injury, sexual assault, placing a person in reasonable apprehension of imminent serious bodily injury, or engaging in behavior that has been or could be enjoined under § 6320 — which the Legislature has expanded to include disturbing the peace of the other party, defined in Rodriguez v. Menjivar (2024) to include coercive control. Orders may include exclusive possession of dwelling (§ 6321), stay-away orders, property control, child custody and visitation (§ 6323), spousal/child support, counseling orders, attorney fees, and other relief necessary to prevent recurrence. Firearms must be relinquished within 24 hours of service under § 6389.',
'["Protective order available on showing of reasonable proof of past act of abuse (§ 6300)","Abuse includes: bodily injury, sexual assault, apprehension of serious injury, disturbing the peace (§ 6203)","Disturbing the peace includes coercive control (Rodriguez v. Menjivar, 2024; § 6320)","Ex parte TRO available without notice to restrained person (§ 6300)","TRO heard same day or next court day (§ 6326)","Hearing on permanent order within 21 days of TRO issuance (§ 6340)","5-year maximum duration for DVRO after hearing (§ 6345(a))","Permanent/lifetime DVRO available in some circumstances (§ 6345)","Renewal before expiration — no new abuse required, only reasonable apprehension (§ 6345(a); Ritchie v. Konrad)","Firearms relinquishment within 24 hours of service (§ 6389)","Proof of firearms surrender or declaration of no firearms (DV-800)","Mutual restraining orders prohibited unless both file separate petitions (§ 6305)","Exclusive possession of dwelling regardless of title (§ 6321)","Custody and visitation orders within DVRO (§ 6323)","CLETS entry mandatory upon issuance (§ 6380)","Criminal penalties for DVRO violation (Penal Code § 273.6)","DV presumption against custody (§ 3044 — triggered by DVRO finding of abuse)","Costs and attorney fees to prevailing petitioner (§ 6344)","Law enforcement must enforce regardless of jurisdiction (§ 6383)","Full faith and credit to out-of-state protective orders (§ 6401, 18 USC § 2265)"]',
'[{"section":"6200-6203","description":"Purpose and definitions — abuse defined, protected persons identified"},{"section":"6211","description":"Domestic violence defined — persons in specified relationships"},{"section":"6300-6306","description":"Issuance of orders — ex parte TRO, mutual order prohibition, order content"},{"section":"6320-6327","description":"Content of orders — stay away, exclusive possession, property, support, counseling"},{"section":"6340-6347","description":"Orders after hearing — duration, modification, costs/fees"},{"section":"6345","description":"Duration and renewal — 5-year max, lifetime option, renewal standard"},{"section":"6380-6389","description":"Registration and enforcement — CLETS entry, law enforcement duties, firearms"},{"section":"6389","description":"Firearms relinquishment — 24-hour deadline, proof required, storage options"},{"section":"6401","description":"Full faith and credit — out-of-state protective orders enforceable"}]',
'["DV-100","DV-109","DV-110","DV-116","DV-120","DV-130","DV-200","DV-250","DV-500","DV-600","DV-700","DV-800","DV-820","CLETS-001","safety_plan","lethality_assessment","DV_declaration","proof_of_service","firearms_receipt"]',
'["dvpa-protective-order-audit","dv-screening-assessment","firearms-relinquishment-compliance","clets-entry-verification"]',
'California Superior Court; Law Enforcement (enforcement)', 1, '1994-01-01', 1, datetime('now'), datetime('now'));


-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 3: Cal. Fam. Code §§ 4000-4339 — Child Support
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_csup_001', 'Child Support Attorney / DCSS Commissioner', 'STATE_STATUTE', 'CA',
'Cal. Fam. Code §§ 4000-4339',
'Fam. Code §§ 4000-4339',
'California Child and Spousal Support — Guideline Formula, Enforcement, Modification',
'California uses a statewide uniform guideline formula under § 4055 to calculate child support. The formula incorporates both parents'' net disposable incomes, custodial timeshare percentages, tax filing status, and mandatory deductions. Section 4057(a) creates a rebuttable presumption that the guideline amount is correct. Courts may deviate only under § 4057(b) factors: stipulation of parties, special circumstances child, high-income parent where formula exceeds child needs, or non-guideline arrangement not harming child. Section 4058 defines income broadly to include all sources: salary, commissions, bonuses, dividends, rental income, trust income, pension benefits, workers'' compensation, unemployment, and earning capacity for voluntarily unemployed/underemployed parents. Spousal support factors under § 4320 include marital standard of living, earning capacity, needs, obligations, assets, duration of marriage, age and health, documented DV history, tax consequences, balance of hardships, and goal of self-support within reasonable period. Gavron warning required under § 4330(b).',
'["Statewide uniform guideline formula is presumptively correct (§ 4055, § 4057(a))","Income broadly defined: all sources including earning capacity (§ 4058)","Imputation of income for voluntary unemployment/underemployment (§ 4058(b))","Net disposable income calculated per § 4059-4060","Hardship deductions for extraordinary health expenses, catastrophic uninsured losses, children from other relationships (§ 4070-4073)","Mandatory add-ons: childcare for employment/training, uninsured healthcare (§ 4062(a))","Discretionary add-ons: educational costs, travel for visitation, special needs (§ 4062(b))","Deviation from guideline only for 5 specified reasons (§ 4057(b))","Earnings assignment order mandatory with every support order (§ 4001)","Support enforceable by contempt (§ 4019)","Interest accrues on arrearages at 10% per year (CCP § 685.010)","Spousal support: 14 factors under § 4320 must be considered","Gavron warning: supported spouse expected to become self-supporting within reasonable time (§ 4330(b))","Richmond factor: reasonable time generally half the length of marriage under 10 years (In re Marriage of Richmond)","Long-term marriage (10+ years): court retains jurisdiction indefinitely unless parties stipulate (§ 4336)","Modification requires material change of circumstances (In re Marriage of Bardzik)","DCSS enforcement: license suspension, tax intercept, passport denial, credit reporting"]',
'[{"section":"4000-4024","description":"Child support enforcement — contempt, earnings assignment, employer duties"},{"section":"4050-4076","description":"Statewide uniform guideline — formula, income, deductions, add-ons, deviation"},{"section":"4055","description":"Guideline formula — CS = K[HN-(H%)(TN)] where K is income allocation based on custody share"},{"section":"4058","description":"Income definition — all sources, imputation for voluntary unemployment"},{"section":"4062","description":"Add-on expenses — mandatory (childcare, healthcare) and discretionary (education, travel)"},{"section":"4200-4204","description":"Effect of support order — retroactivity to filing date"},{"section":"4320-4326","description":"Spousal support factors — 14 factors including marital standard of living, earning capacity, DV"},{"section":"4330-4339","description":"Spousal support orders — Gavron warning, modification, termination on remarriage/death"},{"section":"4336","description":"Long-term marriage — court retains jurisdiction indefinitely for marriages 10+ years"}]',
'["FL-150","FL-155","FL-342","FL-343","FL-530","DissoMaster_printout","earnings_assignment_order","income_documentation","tax_returns","pay_stubs","child_support_modification","spousal_support_order","Gavron_warning","arrears_calculation"]',
'["child-support-guideline-calculation","spousal-support-analysis","support-enforcement-audit","income-verification"]',
