-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 4: Cal. Fam. Code §§ 4320-4326 — Spousal Support Factors
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_spsp_001', 'Family Law Attorney (Dissolution)', 'STATE_STATUTE', 'CA',
'Cal. Fam. Code §§ 4320-4326',
'Fam. Code § 4320',
'California Spousal Support Factors — Marital Standard of Living, Duration, DV',
'Section 4320 sets forth the 14 factors courts must consider when ordering permanent (post-judgment) spousal support. Unlike child support, there is no mathematical formula — the court has broad discretion. The marital standard of living under § 4320(a) is a foundational reference point. Earning capacity must be assessed in light of marketable skills, job market, time/expense for education, and periods during marriage when supported spouse was unemployed for domestic duties or child-rearing. Documented history of domestic violence is a mandatory factor (§ 4320(i)), and conviction under Penal Code § 273.5 creates a rebuttable presumption against support to the perpetrator (§ 4320(i)(1)). For marriages of less than 10 years, the general rule is support for approximately half the length of marriage (In re Marriage of Richmond). For marriages of 10 years or more (''long-term marriage''), the court retains jurisdiction indefinitely unless parties agree otherwise (§ 4336). The Gavron warning under § 4330(b) puts the supported spouse on notice to become self-supporting within a reasonable period.',
'["Court must consider all 14 factors — no single factor dispositive (§ 4320)","Marital standard of living is reference point for support (§ 4320(a))","Earning capacity assessed with marketable skills, job market, education needs (§ 4320(a))","Extent supported spouse contributed to other spouse''s education/career (§ 4320(b))","Ability to pay based on supporting spouse''s earnings and assets (§ 4320(c))","Needs of each party based on marital standard of living (§ 4320(d))","Obligations and assets including separate property (§ 4320(e))","Duration of marriage is major factor (§ 4320(f))","Ability to be gainfully employed without unduly interfering with children''s interests (§ 4320(g))","Age and health of parties (§ 4320(h))","Documented history of domestic violence — mandatory consideration (§ 4320(i))","DV conviction creates presumption against support to perpetrator (§ 4320(i)(1))","Tax consequences to each party (§ 4320(j))","Balance of hardships (§ 4320(k))","Goal: supported spouse becomes self-supporting within reasonable time (§ 4320(l))","Criminal conviction of abusive spouse relevant (§ 4320(m))","Any other just and equitable factors (§ 4320(n))","Long-term marriage (10+ years): jurisdiction retained indefinitely (§ 4336)","Short marriage: approximately half the length of marriage (Richmond guideline)","Gavron warning required (§ 4330(b)) — notice to become self-supporting"]',
'[{"section":"4320(a)","description":"Earning capacity and marital standard of living"},{"section":"4320(b)","description":"Contributions to education/career of other spouse"},{"section":"4320(c)","description":"Ability of supporting spouse to pay"},{"section":"4320(d)","description":"Needs based on marital standard of living"},{"section":"4320(e)","description":"Obligations, assets, separate property"},{"section":"4320(f)","description":"Duration of marriage"},{"section":"4320(g)","description":"Employment vs. care of minor children"},{"section":"4320(h)","description":"Age and health of parties"},{"section":"4320(i)","description":"Documented domestic violence history — mandatory factor, rebuttable presumption against support to perpetrator"},{"section":"4320(j)","description":"Tax consequences"},{"section":"4320(k)","description":"Balance of hardships"},{"section":"4320(l)","description":"Goal of self-support within reasonable time"},{"section":"4320(m)","description":"Criminal conviction of abusive spouse"},{"section":"4320(n)","description":"Other just and equitable factors"},{"section":"4330(b)","description":"Gavron warning — supported spouse must make good faith efforts to become self-supporting"},{"section":"4336","description":"Long-term marriage jurisdiction — court retains indefinitely for 10+ year marriages"}]',
'["FL-150","FL-343","spousal_support_order","Gavron_warning","marital_standard_of_living_analysis","vocational_evaluation","earning_capacity_assessment","DV_documentation_for_support","tax_consequence_analysis","modification_motion"]',
'["spousal-support-analysis","income-verification","marital-standard-of-living-assessment","dv-impact-on-support"]',
'California Superior Court — Family Law Division', 1, '1994-01-01', 1, datetime('now'), datetime('now'));


-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 5: Cal. Fam. Code §§ 2100-2113 — Fiduciary Duties / Disclosure
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_disc_001', 'Family Law Attorney (Dissolution)', 'STATE_STATUTE', 'CA',
'Cal. Fam. Code §§ 2100-2113',
'Fam. Code §§ 2100-2113',
'California Fiduciary Duties and Disclosure Requirements in Dissolution',
'Sections 2100-2113 impose the highest fiduciary duties on spouses during dissolution — the same duties as between partners in a business partnership (§ 721(b)). Section 2100 declares legislative policy: each party has a right to complete and accurate disclosure of all community and separate assets and liabilities. Section 2102 mandates continuing duty to update disclosures until property is distributed. Section 2104 requires service of Preliminary Declaration of Disclosure (FL-140, FL-142, FL-150) within 60 days of filing the response. Section 2105 requires Final Declaration of Disclosure before entry of judgment — waivable only by written agreement under § 2105(d). Section 2107 permits sanctions and evidence exclusion for noncompliance. Sections 2120-2129 provide for set-aside of judgment when material nondisclosure is proven — specifically: § 2122(a) actual fraud (1 year from discovery), § 2122(b) perjury (1 year), § 2122(c) duress (2 years), § 2122(d) mental incapacity (2 years), § 2122(e) mistake (1 year), § 2122(f) failure to comply with disclosure (2 years from discovery). Section 1101 allows action during marriage for breach of fiduciary duty with community property — 100% of undisclosed/transferred asset to the harmed spouse plus attorney fees.',
'["Highest fiduciary duty between spouses — same as business partners (§ 721(b), § 2102)","Complete and accurate disclosure is a right, not a request (§ 2100)","Preliminary Declaration of Disclosure: FL-140, FL-142, FL-150 (§ 2104)","Preliminary disclosure served within 60 days of filing response (§ 2104(f))","Final Declaration of Disclosure before judgment entry (§ 2105)","Final disclosure waiver only by written stipulation (§ 2105(d))","Continuing duty to immediately update all material changes (§ 2102(a))","Must disclose all material facts and information regarding community and separate assets (§ 2102(a))","Must provide access to all income/expense/asset/debt information (§ 2102(b))","Sanctions for noncompliance: attorney fees, evidence preclusion, adverse inferences (§ 2107)","Breach of fiduciary duty during marriage: 100% of asset to harmed spouse (§ 1101(g))","Set-aside for actual fraud — 1 year from discovery (§ 2122(a))","Set-aside for perjury in disclosure — 1 year from discovery (§ 2122(b))","Set-aside for failure to comply with disclosure requirements — 2 years from discovery (§ 2122(f))","Duty to preserve and account for all community property (§ 1100(e))","No unilateral gifts of community property without written consent (§ 1100(b))","Written consent required for any encumbrance/sale of community real property (§ 1102)","Remedy for breach: 50% plus attorneys fees, or 100% for deliberate misappropriation (§ 1101(g)-(h))"]',
'[{"section":"2100","description":"Legislative declaration — right to full disclosure of all assets/liabilities"},{"section":"2101","description":"Duty of good faith and fair dealing in all disclosure matters"},{"section":"2102","description":"Continuing fiduciary duty — immediate update of material changes, access to information"},{"section":"2104","description":"Preliminary declaration of disclosure — FL-140, FL-142, FL-150, 60-day deadline"},{"section":"2105","description":"Final declaration of disclosure — before judgment entry, waiver only by stipulation"},{"section":"2107","description":"Sanctions for noncompliance — attorney fees, evidence preclusion, adverse inferences"},{"section":"2110-2113","description":"Application of duties — commencement of proceeding to final distribution"},{"section":"2120-2129","description":"Set-aside of judgment — fraud, perjury, duress, mental incapacity, failure to disclose"},{"section":"2122","description":"Specific grounds for set-aside — statutes of limitation from discovery"},{"section":"1100","description":"Management of community property — fiduciary duty, no gifts without consent"},{"section":"1101","description":"Action for breach of fiduciary duty — 100% of asset to harmed spouse for deliberate misappropriation"},{"section":"1102","description":"Written consent for encumbrance/sale of community real property"}]',
'["FL-140","FL-141","FL-142","FL-150","FL-160","FL-170","preliminary_disclosure","final_disclosure","schedule_of_assets_debts","income_expense_declaration","property_characterization","community_property_tracing","set_aside_motion","breach_of_fiduciary_duty_action"]',
'["disclosure-compliance-audit","community-property-tracing","fiduciary-duty-analysis","set-aside-analysis"]',
'California Superior Court — Family Law Division', 1, '1994-01-01', 1, datetime('now'), datetime('now'));


-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 6: Cal. Fam. Code §§ 7600-7730 — Parentage / UPA
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_upa_001', 'Paternity Attorney / Genetic Testing Coordinator', 'STATE_STATUTE', 'CA',
'Cal. Fam. Code §§ 7600-7730',
'UPA (Cal. Fam. Code § 7600)',
'California Uniform Parentage Act — Establishment, Presumptions, Genetic Testing, Voluntary Declaration',
'California''s Uniform Parentage Act provides multiple pathways to establish the parent-child relationship. Section 7610 defines how parentage is established: presumption under § 7611, voluntary declaration under § 7570-7577, court adjudication under § 7630-7650, adoption, or gestational surrogacy under § 7960-7962. The marital presumption under § 7540 is conclusive (child born during marriage) and rebuttable only under § 7541 by blood test motion filed within 2 years of birth. Section 7611 establishes the rebuttable presumed parent categories: married at time of birth (§ 7611(a)), attempted marriage (§ 7611(b)), name on birth certificate (§ 7611(c)), and received child into home and held out as own (§ 7611(d)). When two or more presumptions conflict, § 7612(b) requires the court to resolve based on weightier considerations of policy and logic. Genetic testing under §§ 7550-7557 — court may order on motion; probability of 99%+ creates rebuttable presumption of parentage; AABB-accredited lab required. Voluntary declaration of parentage under §§ 7570-7577 has same force as judgment, 60-day rescission period (§ 7575), 2-year challenge period (§ 7576).',
'["Parent-child relationship established by: presumption, voluntary declaration, adjudication, adoption, or surrogacy (§ 7610)","Marital presumption: conclusive for child born during marriage (§ 7540)","Marital presumption rebuttal: blood test motion within 2 years of birth (§ 7541)","Presumed parent categories: married, attempted marriage, birth certificate, received/held out (§ 7611)","Competing presumptions resolved by weightier considerations of policy and logic (§ 7612(b))","Court may recognize more than 2 parents when failure to do so would be detrimental (§ 7612(c))","Genetic testing: court may order on motion of any party (§ 7551)","99%+ probability creates rebuttable presumption of parentage (§ 7555)","AABB-accredited laboratory required for genetic testing (§ 7552)","Voluntary declaration of parentage: same force as judgment (§ 7573)","60-day rescission period for voluntary declaration (§ 7575)","2-year challenge period for voluntary declaration (§ 7576(a))","Challenge after 2 years only for fraud, duress, or material mistake of fact (§ 7576(b))","Action to determine parentage: child, mother, presumed parent, DCSS, interested person (§ 7630)","Judgment of parentage includes custody, visitation, child support (§ 7636)","Birth certificate amendment upon parentage determination (HSC § 102425)","Gestational surrogacy agreement enforced if executed before embryo transfer (§ 7960)","Donor is not a parent unless agreed otherwise (§ 7613(b))"]',
'[{"section":"7540-7541","description":"Marital presumption — conclusive presumption, 2-year rebuttal period"},{"section":"7550-7557","description":"Genetic testing — court-ordered, 99% threshold, AABB lab, chain of custody"},{"section":"7570-7577","description":"Voluntary declaration of parentage — hospital or later, 60-day rescission, 2-year challenge"},{"section":"7600-7612","description":"General provisions — establishment, presumptions, competing presumptions, 3+ parents"},{"section":"7611","description":"Presumed parent — 4 categories: marriage, attempted marriage, birth certificate, received/held out"},{"section":"7612","description":"Rebuttal of presumption — clear and convincing evidence, competing presumption resolution"},{"section":"7613","description":"Donor is not a parent — assisted reproduction, exceptions by agreement"},{"section":"7620-7650","description":"Actions to determine parentage — standing, limitations, jurisdiction, judgment content"},{"section":"7636","description":"Judgment includes custody, visitation, support — full orders upon parentage determination"},{"section":"7700-7730","description":"Adoption of UPA — legislative intent, uniform interpretation"},{"section":"7960-7962","description":"Gestational surrogacy — agreement requirements, pre-birth parentage order"}]',
'["FL-200","FL-210","FL-220","FL-230","FL-235","FL-240","FL-250","CS-909","genetic_test_results","voluntary_declaration_of_parentage","birth_certificate_amendment","parentage_judgment","DCSS_referral","presumed_parent_analysis"]',
'["parentage-determination-audit","genetic-testing-compliance","voluntary-declaration-audit","presumption-analysis"]',
'California Superior Court; DCSS (for IV-D cases)', 1, '1994-01-01', 1, datetime('now'), datetime('now'));


-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 7: Cal. WIC §§ 300-395 — Dependency
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_dep_001', 'Dependency Attorney (Parent/Child/Agency)', 'STATE_STATUTE', 'CA',
'Cal. Welf. & Inst. Code §§ 300-395',
'WIC §§ 300-395',
'California Juvenile Dependency — Child Protection, Removal, Reunification, Permanency',
'The dependency system is the state''s mechanism for protecting children from abuse and neglect when parents cannot or will not. Section 300 establishes 10 grounds for dependency jurisdiction: (a) serious physical harm inflicted nonaccidentally, (b) failure to protect from serious physical harm, (c) serious emotional damage, (d) sexual abuse, (e) severe physical abuse (under 5), (f) death of sibling from abuse/neglect, (g) no provision for support, (h) freed from custody and not placed for adoption, (i) acts of cruelty, (j) sibling has been abused/neglected. Removal from parental custody requires clear and convincing evidence under § 361(c) — substantial danger to physical health, safety, protection, or emotional well-being with no reasonable means to protect without removal. Reunification services are provided for 6/12/18 months depending on child age (§ 361.5). The system moves through mandatory hearing stages: detention (48 hours), jurisdiction (15 days), disposition (10 days after jurisdiction), 6-month review (§ 366.21(e)), 12-month permanency (§ 366.21(f)), 18-month review (§ 366.22), and selection/implementation (§ 366.26 — adoption, guardianship, or long-term foster care). ICWA provides additional protections for Indian children.',
'["10 grounds for dependency jurisdiction (§ 300(a)-(j))","Removal requires clear and convincing evidence of substantial danger (§ 361(c))","No removal if reasonable means to protect child in home (§ 361(c))","Reunification services: 6 months for child under 3, 12 months standard, 18 months maximum (§ 361.5)","Bypass of reunification services for severe abuse, prior TPR, murder of sibling, etc. (§ 361.5(b))","Detention hearing within 48 judicial hours of removal (§ 315)","Jurisdiction hearing within 15 court days of detention (CRC 5.686)","Disposition within 10 court days of jurisdiction (CRC 5.686)","6-month review hearing (§ 366.21(e)) — return home if safe, continue services, or set permanency","12-month permanency hearing (§ 366.21(f)) — return home or set § 366.26 hearing","18-month review (§ 366.22) — last extension of services, must return or set permanency","§ 366.26 hearing — TPR and adoption, legal guardianship, or planned permanent living arrangement","§ 366.26 hearing within 120 days of permanency setting","Relative placement preference (§ 361.3) — relatives given preferential consideration","ICWA compliance mandatory at every hearing — inquiry, notice, active efforts, qualified expert witness","Reasonable efforts finding required at every hearing (§ 366)","ASFA 15/22 month rule — TPR petition if child in foster care 15 of last 22 months (42 USC § 675(5)(E))","Sibling placement presumption (§ 16002)","Child''s right to counsel (§ 317(c))","Parent''s right to counsel (§ 317)"]',
'[{"section":"300(a)-(j)","description":"Grounds for dependency jurisdiction — 10 categories of abuse/neglect"},{"section":"305-315","description":"Temporary custody and detention — emergency removal, 48-hour hearing"},{"section":"319","description":"Detention hearing — prima facie showing, reasonable efforts, ICWA inquiry"},{"section":"355-358","description":"Jurisdiction hearing — preponderance of evidence for jurisdiction"},{"section":"358-362","description":"Disposition — case plan, reasonable efforts, removal by clear and convincing evidence"},{"section":"361","description":"Removal — clear and convincing evidence, no reasonable means to protect without removal"},{"section":"361.3","description":"Relative placement preference — preferential consideration of relatives"},{"section":"361.5","description":"Reunification services — timelines, bypass provisions"},{"section":"366.21","description":"Review hearings — 6-month and 12-month reviews, return or permanency"},{"section":"366.22","description":"18-month review — last extension, return or permanency"},{"section":"366.26","description":"Selection and implementation — TPR/adoption, guardianship, or PPLA"},{"section":"366.3","description":"Post-permanency review — guardianship or PPLA review hearings"},{"section":"388","description":"Modification petition — changed circumstances, best interest of child"},{"section":"395","description":"Appeal rights — right to appeal from any order or judgment"}]',
'["JV-100","JV-110","JV-215","JV-320","JV-321","JV-400","JV-410","JV-415","JV-421","JV-180","JV-505","ICWA-010","ICWA-020","ICWA-030","detention_report","jurisdiction_disposition_report","status_review_report","permanency_plan","366_26_report","case_plan","safety_assessment","risk_assessment"]',
'["dependency-petition-audit","reunification-compliance","permanency-planning","icwa-compliance","child-removal-analysis"]',
'California Superior Court — Juvenile Division; CDSS; County Child Welfare Agencies', 1, '1987-01-01', 1, datetime('now'), datetime('now'));


-- ──────────────────────────────────────────────────────────────────────────
-- STANDARD 8: CRC Rules 5.210-5.487 — Family Law Rules of Court
-- ──────────────────────────────────────────────────────────────────────────

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, effective_date, is_active, created_at, updated_at)
VALUES
('std_fam_crc_001', 'Attorney at Law (Family Law) / Certified Family Law Specialist', 'COURT_RULE', 'CA',
'Cal. Rules of Court 5.210-5.487',
'CRC Title 5',
'California Rules of Court — Family Law Proceedings Rules',
'Title 5 of the California Rules of Court governs all family law proceedings in Superior Court. Rules 5.210-5.215 govern family court services mediation and mediator qualifications. Rule 5.220 sets comprehensive standards for court-ordered child custody evaluations including scope, methodology, evaluator qualifications, DV screening, report format, and distribution. Rules 5.225-5.230 govern private evaluator appointments and training. Rules 5.240-5.242 govern appointment and duties of minor''s counsel. Rules 5.250-5.260 address hearings and testimony procedures per Elkins v. Superior Court — parties have the right to live testimony, not just declarations. Rules 5.300-5.375 govern child support proceedings, family law facilitator duties, and DCSS proceedings. Rules 5.380-5.401 cover postjudgment motions and enforcement. Rules 5.410-5.440 cover domestic violence prevention proceedings. Rules 5.450-5.487 address special proceedings including nullity, legal separation, parentage, and governmental actions. All family law filings must comply with mandatory Judicial Council forms where designated.',
'["Mandatory mediation before contested custody hearing (CRC 5.210, Fam. Code § 3170)","Mediator qualifications: master''s degree, experience, DV training (CRC 5.210)","Custody evaluation standards: scope, methodology, DV screening, report format (CRC 5.220)","Evaluator must screen for DV in every evaluation (CRC 5.220(f))","Private evaluator held to same standards as court-connected (CRC 5.225)","Evaluator training: 40 hours DV, 16 hours child abuse, ongoing education (CRC 5.230)","Minor''s counsel duties: investigation, report, recommendation, best interest (CRC 5.242)","Right to live testimony per Elkins — not just declarations (CRC 5.250-5.260)","Request for order must be filed on Judicial Council mandatory forms (CRC 5.92)","Income and expense declaration required with every support motion (CRC 5.260)","Child support: guideline calculation printout required (CRC 5.275)","DCSS proceedings: notice, hearing, commissioner authority (CRC 5.300-5.375)","Family law facilitator: assist self-represented litigants with forms and information (CRC 5.350)","DV proceedings: forms, service, hearing procedures (CRC 5.410-5.440)","Temporary emergency orders (ex parte) — narrow grounds, notice requirements (CRC 5.151-5.169)","Continuance standards — good cause required, child''s best interest considered (CRC 5.95)","Local court rules may supplement but not conflict with CRC Title 5"]',
'[{"section":"5.210-5.215","description":"Family court services mediation — qualifications, DV protocols, recommending counties"},{"section":"5.220","description":"Custody evaluations — scope, methodology, DV screening, report content, distribution, confidentiality"},{"section":"5.225-5.230","description":"Private evaluators and training requirements"},{"section":"5.240-5.242","description":"Minor''s counsel — appointment, duties, access, reporting"},{"section":"5.250-5.260","description":"Hearings — Elkins compliance, live testimony, evidence, income/expense declarations"},{"section":"5.275","description":"Child support — guideline calculation worksheet, DissoMaster printout requirement"},{"section":"5.300-5.375","description":"Child support proceedings — facilitator duties, DCSS procedures, commissioner authority"},{"section":"5.380-5.401","description":"Postjudgment motions — modification, enforcement, contempt"},{"section":"5.410-5.440","description":"Domestic violence — DV proceeding rules, forms, service, hearings, renewals"},{"section":"5.450-5.487","description":"Special proceedings — nullity, legal separation, parentage, governmental actions"},{"section":"5.92","description":"Mandatory Judicial Council forms — must use designated forms for specified proceedings"},{"section":"5.95","description":"Continuances — good cause, child best interest, trial readiness"},{"section":"5.111-5.125","description":"Document format — caption, page layout, attachments, form numbering"},{"section":"5.151-5.169","description":"Temporary emergency (ex parte) orders — grounds, notice, procedure"}]',
'["FL-100","FL-110","FL-120","FL-300","FL-320","FL-150","FL-311","FL-341","FL-342","FL-343","DV-100","DV-130","JV-100","custody_evaluation_order","mediation_referral","minor_counsel_appointment","facilitator_referral","mandatory_form_compliance_check"]',
'["family-law-procedure-audit","mandatory-form-compliance","elkins-compliance","custody-evaluation-standards","mediation-compliance","dv-proceedings-audit"]',
'California Judicial Council; Superior Court — Family Law Division', 0, '2003-01-01', 1, datetime('now'), datetime('now'));


